   541 |                                  Value *FalseVal,
   542 |                                  bool Swapped) -> Instruction * {
   543 |     auto *TVI = dyn_cast<BinaryOperator>(TrueVal);
   544 |     if (!TVI || !TVI->hasOneUse() || isa<Constant>(FalseVal))
   545 |       return nullptr;
   546 | 
   547 |     unsigned SFO = getSelectFoldableOperands(TVI);
   548 |     unsigned OpToFold = 0;
   549 |     if ((SFO & 1) && FalseVal == TVI->getOperand(0))
   550 |       OpToFold = 1;
   551 |     else if ((SFO & 2) && FalseVal == TVI->getOperand(1))
   552 |       OpToFold = 2;
   553 | 
   554 |     if (!OpToFold)
