   604 | /// We want to turn:
   605 | ///   (select (icmp eq (and X, Y), 0), (and (lshr X, Z), 1), 1)
   606 | /// into:
   607 | ///   zext (icmp ne i32 (and X, (or Y, (shl 1, Z))), 0)
   608 | /// Note:
   609 | ///   Z may be 0 if lshr is missing.
   610 | /// Worst-case scenario is that we will replace 5 instructions with 5 different
   611 | /// instructions, but we got rid of select.
   612 | static Instruction *foldSelectICmpAndAnd(Type *SelType, const ICmpInst *Cmp,
   613 |                                          Value *TVal, Value *FVal,
   614 |                                          InstCombiner::BuilderTy &Builder) {
   615 |   if (!(Cmp->hasOneUse() && Cmp->getOperand(0)->hasOneUse() &&
   616 |         Cmp->getPredicate() == ICmpInst::ICMP_EQ &&
   617 |         match(Cmp->getOperand(1), m_Zero()) && match(FVal, m_One())))
   618 |     return nullptr;
   619 | 
   620 |   // The TrueVal has general form of:  and %B, 1
   621 |   Value *B;
   622 |   if (!match(TVal, m_OneUse(m_And(m_Value(B), m_One()))))
   623 |     return nullptr;
   624 | 
   625 |   // Where %B may be optionally shifted:  lshr %X, %Z.
   626 |   Value *X, *Z;
   627 |   const bool HasShift = match(B, m_OneUse(m_LShr(m_Value(X), m_Value(Z))));
   628 | 
   629 |   // The shift must be valid.
   630 |   // TODO: This restricts the fold to constant shift amounts. Is there a way to
   631 |   //       handle variable shifts safely? PR47012
   632 |   if (HasShift &&
   633 |       !match(Z, m_SpecificInt_ICMP(CmpInst::ICMP_ULT,
   634 |                                    APInt(SelType->getScalarSizeInBits(),
   635 |                                          SelType->getScalarSizeInBits()))))
   636 |     return nullptr;
   637 | 
   638 |   if (!HasShift)
   639 |     X = B;
   640 | 
   641 |   Value *Y;
   642 |   if (!match(Cmp->getOperand(0), m_c_And(m_Specific(X), m_Value(Y))))
   643 |     return nullptr;
   644 | 
   645 |   // ((X & Y) == 0) ? ((X >> Z) & 1) : 1 --> (X & (Y | (1 << Z))) != 0
   646 |   // ((X & Y) == 0) ? (X & 1) : 1 --> (X & (Y | 1)) != 0
   647 |   Constant *One = ConstantInt::get(SelType, 1);
   648 |   Value *MaskB = HasShift ? Builder.CreateShl(One, Z) : One;
   649 |   Value *FullMask = Builder.CreateOr(Y, MaskB);
   650 |   Value *MaskedX = Builder.CreateAnd(X, FullMask);

