  1309 | Instruction *InstCombinerImpl::foldSelectValueEquivalence(SelectInst &Sel,
  1310 |                                                           ICmpInst &Cmp) {
  1311 |   if (!Cmp.isEquality())
  1312 |     return nullptr;
  1313 | 
  1314 |   // Canonicalize the pattern to ICMP_EQ by swapping the select operands.
  1315 |   Value *TrueVal = Sel.getTrueValue(), *FalseVal = Sel.getFalseValue();
  1316 |   bool Swapped = false;
  1317 |   if (Cmp.getPredicate() == ICmpInst::ICMP_NE) {
  1318 |     std::swap(TrueVal, FalseVal);
  1319 |     Swapped = true;
  1320 |   }
  1321 | 
  1322 |   Value *CmpLHS = Cmp.getOperand(0), *CmpRHS = Cmp.getOperand(1);
  1323 |   auto ReplaceOldOpWithNewOp = [&](Value *OldOp,
  1324 |                                    Value *NewOp) -> Instruction * {
  1325 |     // In X == Y ? f(X) : Z, try to evaluate f(Y) and replace the operand.
  1326 |     // Take care to avoid replacing X == Y ? X : Z with X == Y ? Y : Z, as that
  1327 |     // would lead to an infinite replacement cycle.
  1328 |     // If we will be able to evaluate f(Y) to a constant, we can allow undef,
  1329 |     // otherwise Y cannot be undef as we might pick different values for undef
  1330 |     // in the icmp and in f(Y).
  1331 |     if (TrueVal == OldOp)
  1332 |       return nullptr;
  1333 | 
  1334 |     if (Value *V = simplifyWithOpReplaced(TrueVal, OldOp, NewOp, SQ,
  1335 |                                           /* AllowRefinement=*/true)) {
  1336 |       // Need some guarantees about the new simplified op to ensure we don't inf
  1337 |       // loop.
  1338 |       // If we simplify to a constant, replace if we aren't creating new undef.
  1339 |       if (match(V, m_ImmConstant()) &&
  1340 |           isGuaranteedNotToBeUndef(V, SQ.AC, &Sel, &DT))
  1341 |         return replaceOperand(Sel, Swapped ? 2 : 1, V);
  1342 | 
  1343 |       // If NewOp is a constant and OldOp is not replace iff NewOp doesn't
  1344 |       // contain and undef elements.
  1345 |       if (match(NewOp, m_ImmConstant()) || NewOp == V) {
  1346 |         if (isGuaranteedNotToBeUndef(NewOp, SQ.AC, &Sel, &DT))
  1347 |           return replaceOperand(Sel, Swapped ? 2 : 1, V);
  1348 |         return nullptr;
  1349 |       }
  1350 |     }
  1351 | 
  1352 |     // Even if TrueVal does not simplify, we can directly replace a use of
  1353 |     // CmpLHS with CmpRHS, as long as the instruction is not used anywhere
  1354 |     // else and is safe to speculatively execute (we may end up executing it
  1355 |     // with different operands, which should not cause side-effects or trigger
  1356 |     // undefined behavior). Only do this if CmpRHS is a constant, as
  1357 |     // profitability is not clear for other cases.
